ftstest.c
=========

#include <fts.h>
#include <stdio.h>
#include <sys/stat.h>

int
main(void) {
	FTS *fts;
	FTSENT *e;
	char *path = "/etc";
	char * const path_argv[] = { path, NULL };

	if ((fts = fts_open(path_argv, FTS_LOGICAL, NULL)) == NULL) {
		printf("fts_open error: %s\n", path);
		return (1);
	}
	fts_close(fts);
	return (0);
}



If 'fts_read' is called before 'fts_close' no complaints from vagrind.

